import React, { useState, useEffect } from 'react';

export default function Settings() {
  const [claudeKey, setClaudeKey] = useState('');
  const [saved, setSaved] = useState(false);

  useEffect(() => {
    const savedKey = localStorage.getItem('claude_api_key');
    if (savedKey) {
      setClaudeKey(savedKey);
    }
  }, []);

  const handleSave = () => {
    localStorage.setItem('claude_api_key', claudeKey);
    setSaved(true);
    setTimeout(() => setSaved(false), 2000);
  };

  const handleClear = () => {
    localStorage.removeItem('claude_api_key');
    setClaudeKey('');
    setSaved(true);
    setTimeout(() => setSaved(false), 2000);
  };

  return (
    <div className="settings" style={{ maxWidth: '600px', margin: '0 auto', textAlign: 'left' }}>
      <h2>⚙️ Settings</h2>

      <div style={{ 
        background: 'rgba(22,27,34,0.8)', 
        border: '1px solid rgba(139,148,158,0.15)', 
        borderRadius: '16px', 
        padding: '2rem',
        marginTop: '1rem'
      }}>
        <h3 style={{ color: '#e6edf3', marginBottom: '1rem' }}>🔑 Claude API</h3>
        <p style={{ color: '#8b949e', fontSize: '0.875rem', marginBottom: '1rem' }}>
          Enter your Claude API key for cloud AI fallback. Get one at{' '}
          <a 
            href="https://console.anthropic.com" 
            target="_blank" 
            rel="noopener noreferrer"
            style={{ color: '#38bdf8' }}
          >
            console.anthropic.com
          </a>
        </p>

        <div className="form-group">
          <label>Claude API Key</label>
          <input
            type="password"
            value={claudeKey}
            onChange={(e) => setClaudeKey(e.target.value)}
            placeholder="sk-ant-..."
            style={{
              width: '100%',
              padding: '0.875rem 1rem',
              background: 'rgba(0,0,0,0.4)',
              border: '1px solid rgba(139,148,158,0.25)',
              borderRadius: '10px',
              color: '#fff',
              fontSize: '0.9rem'
            }}
          />
        </div>

        <div style={{ display: 'flex', gap: '1rem', marginTop: '1rem' }}>
          <button 
            onClick={handleSave}
            style={{
              background: 'linear-gradient(135deg, #238636 0%, #2ea043 100%)',
              color: 'white',
              border: 'none',
              padding: '0.75rem 1.5rem',
              borderRadius: '10px',
              fontWeight: '600',
              cursor: 'pointer'
            }}
          >
            {saved ? '✓ Saved!' : 'Save Key'}
          </button>

          <button 
            onClick={handleClear}
            style={{
              background: 'rgba(210,153,34,0.15)',
              color: '#d29922',
              border: '1px solid rgba(210,153,34,0.3)',
              padding: '0.75rem 1.5rem',
              borderRadius: '10px',
              fontWeight: '600',
              cursor: 'pointer'
            }}
          >
            Clear Key
          </button>
        </div>
      </div>

      <div style={{ 
        background: 'rgba(22,27,34,0.8)', 
        border: '1px solid rgba(139,148,158,0.15)', 
        borderRadius: '16px', 
        padding: '2rem',
        marginTop: '1.5rem'
      }}>
        <h3 style={{ color: '#e6edf3', marginBottom: '1rem' }}>ℹ️ About</h3>
        <p style={{ color: '#8b949e', fontSize: '0.875rem' }}>
          <strong style={{ color: '#e6edf3' }}>HOMAI</strong> — AI Real Estate Operating System
        </p>
        <p style={{ color: '#6e7681', fontSize: '0.8rem', marginTop: '0.5rem' }}>
          Local-first AI with cloud fallback. Your data stays on your machine.
        </p>
      </div>

      <div style={{ 
        background: 'rgba(22,27,34,0.8)', 
        border: '1px solid rgba(139,148,158,0.15)', 
        borderRadius: '16px', 
        padding: '2rem',
        marginTop: '1.5rem'
      }}>
        <h3 style={{ color: '#e6edf3', marginBottom: '1rem' }}>🔌 API Connections</h3>

        <div style={{ display: 'grid', gap: '0.75rem' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <span style={{ color: '#8b949e' }}>Ollama (Qwen)</span>
            <span style={{ color: '#3fb950' }}>🟢 Connected</span>
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <span style={{ color: '#8b949e' }}>Claude API</span>
            <span style={{ color: claudeKey ? '#3fb950' : '#6e7681' }}>
              {claudeKey ? '🟢 Configured' : '⚪ Not set'}
            </span>
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <span style={{ color: '#8b949e' }}>PostgreSQL</span>
            <span style={{ color: '#3fb950' }}>🟢 Online</span>
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <span style={{ color: '#8b949e' }}>Vector DB</span>
            <span style={{ color: '#3fb950' }}>🟢 Online</span>
          </div>
        </div>
      </div>
    </div>
  );
}
